### 최적화 5. GraphQL N+1 방지 (DataLoader)

GraphQL에서 통화 목록 조회 시 각 통화마다 상대방 유저 정보를 개별 조회하는 경우를 방지합니다.

**After (개선 코드):**

```kotlin
// graphql/src/main/kotlin/com/maum/backend/dataloader/UserDataLoader.kt
@Component
class UserDataLoader(
    private val userService: UserService,
) : BatchLoader<String, UserInfo> {

    override fun load(userIds: List<String>): CompletionStage<List<UserInfo>> {
        return CompletableFuture.supplyAsync {
            // 단일 gRPC 배치 호출로 N명 유저 한 번에 조회
            userService.getUsersByIds(userIds)
        }
    }
}

// graphql/src/main/kotlin/com/maum/backend/controller/call/CallController.kt
@Controller
class CallController(
    private val callService: CallService,
    private val userDataLoader: UserDataLoader,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun callHistory(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): List<CallHistoryResponse> {
        val calls = callService.getCallHistory(userId, limit ?: 20, offset ?: 0)

        // DataLoader로 유저 정보 배치 조회 (N+1 방지)
        val userIds = calls.callsList.map { it.opponentUserId }.distinct()
        val usersById = userDataLoader.loadMany(userIds).get()
            .zip(userIds)
            .associate { (user, id) -> id to user }

        return calls.callsList.map { call ->
            call.toResponse(opponent = usersById[call.opponentUserId])
        }
    }
}
```

