### 최적화 1. fetch join + QueryDSL Projection으로 N+1 제거

**After (개선 코드):**

```kotlin
// domain/src/main/kotlin/com/maum/backend/repository/call/CallWaitingCustomRepository.kt
interface CallWaitingCustomRepository {
    fun findMatchCandidatesExcludingBlocked(
        requestUserId: String,
        targetGender: Int,
        limit: Int,
    ): List<CallWaitingWithUserDto>
}

// domain/src/main/kotlin/com/maum/backend/repository/call/CallWaitingCustomRepositoryImpl.kt
class CallWaitingCustomRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
) : CallWaitingCustomRepository {

    override fun findMatchCandidatesExcludingBlocked(
        requestUserId: String,
        targetGender: Int,
        limit: Int,
    ): List<CallWaitingWithUserDto> {
        val waiting = QCallWaitingEntity.callWaitingEntity
        val user = QUserEntity.userEntity
        val block = QBlockEntity.blockEntity

        return queryFactory
            .select(
                Projections.constructor(
                    CallWaitingWithUserDto::class.java,
                    waiting.id,
                    waiting.userId,
                    user.nickname,
                    user.age,
                    user.profileImageUrl,
                    waiting.createdAt,
                )
            )
            .from(waiting)
            .innerJoin(user).on(
                user.id.eq(waiting.userId),
                user.status.eq(0),        // 활성 유저만
                user.gender.eq(targetGender),
            )
            .leftJoin(block).on(
                block.fromUserId.eq(requestUserId),
                block.toUserId.eq(waiting.userId),
            )
            .where(
                waiting.status.eq(0),     // 대기 중
                block.id.isNull,          // 차단하지 않은 유저
                waiting.userId.ne(requestUserId),
            )
            .orderBy(waiting.createdAt.asc())
            .limit(limit.toLong())
            .fetch()
    }
}
```

