### 최적화 2. Redis 캐시로 매칭 상태 조회 최적화

**After (개선 코드):**

```kotlin
// call/src/main/kotlin/com/maum/backend/service/CallWaitingCacheService.kt
@Service
class CallWaitingCacheService(
    private val redisTemplate: RedisTemplate<String, String>,
) {
    companion object {
        private const val WAITING_KEY_PREFIX = "call:waiting:"
        private const val WAITING_TTL_SECONDS = 300L  // 5분
        private const val MATCH_RESULT_KEY_PREFIX = "call:match:"
        private const val MATCH_RESULT_TTL_SECONDS = 60L  // 1분
    }

    // 대기 등록 시 Redis에도 저장
    fun registerWaiting(userId: String, waitingId: String) {
        val key = "$WAITING_KEY_PREFIX$userId"
        redisTemplate.opsForValue().set(key, waitingId, Duration.ofSeconds(WAITING_TTL_SECONDS))
    }

    // 매칭 상태 확인 (DB 대신 Redis 조회)
    fun getWaitingId(userId: String): String? {
        return redisTemplate.opsForValue().get("$WAITING_KEY_PREFIX$userId")
    }

    // 매칭 완료 결과 캐싱
    fun cacheMatchResult(userId: String, matchedUserId: String, roomId: String) {
        val key = "$MATCH_RESULT_KEY_PREFIX$userId"
        val value = "$matchedUserId:$roomId"
        redisTemplate.opsForValue().set(key, value, Duration.ofSeconds(MATCH_RESULT_TTL_SECONDS))
    }

    fun getMatchResult(userId: String): MatchResultCache? {
        val value = redisTemplate.opsForValue().get("$MATCH_RESULT_KEY_PREFIX$userId") ?: return null
        val parts = value.split(":")
        return MatchResultCache(matchedUserId = parts[0], roomId = parts[1])
    }

    // 대기 취소/매칭 완료 시 무효화
    fun invalidateWaiting(userId: String) {
        redisTemplate.delete("$WAITING_KEY_PREFIX$userId")
    }
}
```

```kotlin
